$(function(){
  var nameMap={'airine':'艾莉尼','bathsheba':'拔示巴','lena':'蕾娜','meme':'米姆','belzeebul':'贝尔泽布特'};
  var lastMood='';

  function createDOM(){
    if(document.getElementById('ml-sb'))return;
    var d=document.createElement('div');
    d.id='ml-sb';
    d.innerHTML='<style>#ml-sb{background:#0a0a14;color:#d0d0e8;font:12px Segoe UI,Microsoft YaHei,sans-serif;padding:10px 12px;max-width:300px;border:1px solid #1e1e3a;border-radius:8px;margin:8px auto}#ml-sb .h{font-size:14px;font-weight:700;color:#7c8aff;margin-bottom:8px;text-align:center}#ml-sb .r{display:flex;justify-content:space-between;padding:3px 0;border-bottom:1px solid rgba(255,255,255,0.04)}#ml-sb .l{color:#7070a0;font-size:11px}#ml-sb .v{text-align:right}#ml-sb .bar{height:4px;background:rgba(255,255,255,0.06);border-radius:2px;margin:2px 0}#ml-sb .fill{height:100%;border-radius:2px;transition:width .4s}#ml-sb .al{font-size:10px;color:#7070a0}#ml-sb .thought{margin-top:6px;padding:6px 8px;background:#12122a;border-radius:4px;font-style:italic;color:#7070a0;font-size:11px;line-height:1.4;border-left:2px solid #1e1e3a}</style><div class="h" id="mln">--</div><div class="r"><span class="l">好感度</span><span class="v" id="mlav">0/100</span></div><div class="bar"><div class="fill" id="mlab" style="width:0;background:#7070a0"></div></div><div class="al" id="mlal">陌生人</div><div class="r"><span class="l">心情</span><span class="v" id="mlmo">--</span></div><div class="r"><span class="l">穿着</span><span class="v" id="mlcl">--</span></div><div class="thought" id="mlth">...</div>';
    var msgs=document.querySelectorAll('.mes,.mes_text,.chat_msg');
    if(msgs.length>0)msgs[msgs.length-1].appendChild(d);
    else document.body.appendChild(d);
  }

  function parseJsonPatch(text){
    var match=text.match(/<JSONPatch>\s*\[([\s\S]*?)\]\s*<\/JSONPatch>/);
    if(!match)return null;
    try{return JSON.parse('['+match[1]+']');}catch(e){return null;}
  }

  function apply(data, patches){
    if(!patches)return data;
    for(var i=0;i<patches.length;i++){
      var p=patches[i];
      if(!p.path||p.path.indexOf('/stat_data/')!==0)continue;
      var parts=p.path.replace('/stat_data/','').split('/');
      // Navigate to the right nested object
      var target=data;
      for(var j=0;j<parts.length-1;j++){
        if(!target[parts[j]])target[parts[j]]={};
        target=target[parts[j]];
      }
      var key=parts[parts.length-1];
      if(p.op==='replace')target[key]=p.value;
      else if(p.op==='delta')target[key]=(Number(target[key])||0)+Number(p.value||0);
    }
    return data;
  }

  function scan(){
    createDOM();
    var $=function(id){return document.getElementById(id)};
    var t=function(id,v){var el=$(id);if(el)el.textContent=v!=null?String(v):'--'};

    try{
      var chat=parent.SillyTavern.getContext().chat;
      if(!chat||!chat.length)return;

      // Get character name from first message
      var sc='';
      for(var i=0;i<Math.min(chat.length,3);i++){
        var m=chat[i].mes||'';
        var mc=m.match(/已选择角色[：:]\s*(.+?)[，,\n]/);
        if(mc){sc=mc[1].trim();break}
      }

      // Parse patches from all messages to build cumulative state
      var state={characters:{}};
      for(var i=0;i<chat.length;i++){
        var patches=parseJsonPatch(chat[i].mes||'');
        if(patches&&patches.length)apply(state,patches);
      }

      // Also try to get selected_character from patches
      for(var i=0;i<chat.length;i++){
        var patches=parseJsonPatch(chat[i].mes||'');
        if(patches)for(var j=0;j<patches.length;j++){
          if(patches[j].path==='/stat_data/selected_character'&&patches[j].value){
            sc=patches[j].value;
          }
        }
      }

      if(!sc){t('mln','--');return;}
      var cd=(state.characters||{})[sc]||{};
      var aff=Number(cd.affection)||0;
      var ac,al;
      if(aff>=81){ac='#ff7eb3';al='无条件信任'}
      else if(aff>=61){ac='#7c8aff';al='深厚信赖'}
      else if(aff>=41){ac='#4ade80';al='熟悉亲近'}
      else if(aff>=21){ac='#fbbf24';al='初步信任'}
      else{ac='#7070a0';al='陌生人'}

      var mood=cd.mood||'--';
      if(mood===lastMood)return;
      lastMood=mood;

      t('mln',nameMap[sc]||cd.name||sc);
      $('mlav').textContent=aff+'/100';
      $('mlab').style.width=aff+'%';
      $('mlab').style.background=ac;
      t('mlal',al);
      t('mlmo',mood);
      t('mlcl',cd.clothing||'--');
      t('mlth',cd.inner_thought||'...');
    }catch(e){}
  }

  // Scan on each new message
  if(typeof eventOn==='function'){
    eventOn('MESSAGE_RECEIVED',function(){setTimeout(scan,2000);});
    eventOn('MESSAGE_SENT',function(){setTimeout(scan,2000);});
  }
  // Initial scan with retry
  setTimeout(scan,3000);
  setTimeout(scan,6000);
  setTimeout(scan,10000);
});
